// ============================================
// ANOMALY DETECTOR v2 - With state machine integration
// ============================================
// Now pauses teasers with critical anomalies via state machine.
// BOT_TRAFFIC insight: high bot % = can pay less (signal for lower bids).

const items = $input.all();
const anomalies = [];
const DEVIATION_THRESHOLD = 2;

items.forEach(item => {
  const d = item.json;
  if (!d.ad_id) return;

  // CTR anomaly - sudden drop
  if (d.std_ctr_7d > 0 && d.avg_ctr_7d > 0) {
    const ctrDeviation = (d.today_ctr - d.avg_ctr_7d) / d.std_ctr_7d;
    if (ctrDeviation < -DEVIATION_THRESHOLD) {
      anomalies.push({
        ad_id: d.ad_id,
        type: 'CTR_DROP',
        severity: 'warning',
        description: `CTR dropped: ${d.today_ctr?.toFixed(4)}% vs avg ${d.avg_ctr_7d?.toFixed(4)}%`,
        metric: 'ctr',
        expected: d.avg_ctr_7d,
        actual: d.today_ctr,
        deviation: Math.round(ctrDeviation * 100) / 100,
        should_pause: false
      });
    }
    if (ctrDeviation > DEVIATION_THRESHOLD) {
      anomalies.push({
        ad_id: d.ad_id,
        type: 'CTR_SPIKE',
        severity: 'positive',
        description: `CTR spiked! ${d.today_ctr?.toFixed(4)}% vs avg ${d.avg_ctr_7d?.toFixed(4)}% - consider scaling`,
        metric: 'ctr',
        expected: d.avg_ctr_7d,
        actual: d.today_ctr,
        deviation: Math.round(ctrDeviation * 100) / 100,
        should_pause: false
      });
    }
  }

  // CPC anomaly - competition spike
  if (d.std_cpc_7d > 0 && d.avg_cpc_7d > 0) {
    const cpcDeviation = (d.today_cpc - d.avg_cpc_7d) / d.std_cpc_7d;
    if (cpcDeviation > DEVIATION_THRESHOLD) {
      anomalies.push({
        ad_id: d.ad_id,
        type: 'CPC_SPIKE',
        severity: 'warning',
        description: `CPC spiked: $${d.today_cpc?.toFixed(4)} vs avg $${d.avg_cpc_7d?.toFixed(4)} - competition increased?`,
        metric: 'cpc',
        expected: d.avg_cpc_7d,
        actual: d.today_cpc,
        deviation: Math.round(cpcDeviation * 100) / 100,
        should_pause: false
      });
    }
  }

  // Zero shows - block might be down
  if (d.today_shows === 0 && d.avg_clicks_7d > 5) {
    anomalies.push({
      ad_id: d.ad_id,
      type: 'ZERO_SHOWS',
      severity: 'critical',
      description: `No shows today but avg ${d.avg_clicks_7d?.toFixed(0)} clicks/day - block down?`,
      metric: 'shows',
      expected: d.avg_clicks_7d,
      actual: 0,
      deviation: -100,
      should_pause: false  // Don't pause, might be temporary
    });
  }

  // Bot traffic: many clicks but zero conversions with significant spend
  if (d.today_clicks > 20 && d.today_conversions === 0 && d.avg_conversions_7d > 1) {
    const botSeverity = d.today_spend > 30 ? 'critical' : 'warning';
    anomalies.push({
      ad_id: d.ad_id,
      type: 'BOT_TRAFFIC',
      severity: botSeverity,
      description: `${d.today_clicks} clicks, 0 conversions (avg ${d.avg_conversions_7d?.toFixed(1)}/day), $${d.today_spend?.toFixed(2)} spent - bot traffic`,
      metric: 'conversions',
      expected: d.avg_conversions_7d,
      actual: 0,
      deviation: -100,
      should_pause: botSeverity === 'critical'  // PAUSE if critical bot traffic
    });
  }

  // Clicks without shows ratio (click fraud)
  if (d.today_shows > 0 && d.today_clicks > 0) {
    const clickRate = d.today_clicks / d.today_shows * 100;
    if (clickRate > 10 && d.today_clicks > 30) {
      anomalies.push({
        ad_id: d.ad_id,
        type: 'CLICK_FRAUD',
        severity: 'critical',
        description: `Suspicious CTR ${clickRate.toFixed(1)}% (${d.today_clicks} clicks / ${d.today_shows} shows) - possible click fraud`,
        metric: 'ctr',
        expected: d.avg_ctr_7d || 0.5,
        actual: clickRate,
        deviation: 999,
        should_pause: true  // PAUSE - definite fraud
      });
    }
  }
});

if (anomalies.length === 0) return [];

return anomalies.map(a => ({ json: a }));

const anomalies = $input.all().map(i => i.json);

const critical = anomalies.filter(a => a.severity === 'critical');
const warnings = anomalies.filter(a => a.severity === 'warning');
const positive = anomalies.filter(a => a.severity === 'positive');
const paused = anomalies.filter(a => a.should_pause);

let msg = `ANOMALY DETECTOR v2 ${$now.toFormat('dd.MM.yyyy HH:mm')}\n\n`;
msg += `Found ${anomalies.length} anomalies`;
if (paused.length > 0) msg += ` | ${paused.length} teasers PAUSED`;
msg += `\n\n`;

if (paused.length > 0) {
  msg += `PAUSED (anomaly):\n`;
  paused.forEach(a => msg += `  #${a.ad_id}: ${a.description}\n`);
  msg += `\n`;
}

if (critical.length > 0) {
  msg += `CRITICAL:\n`;
  critical.filter(a => !a.should_pause).forEach(a => msg += `  #${a.ad_id}: ${a.description}\n`);
  msg += `\n`;
}
if (warnings.length > 0) {
  msg += `WARNINGS:\n`;
  warnings.forEach(a => msg += `  #${a.ad_id}: ${a.description}\n`);
  msg += `\n`;
}
if (positive.length > 0) {
  msg += `OPPORTUNITIES:\n`;
  positive.forEach(a => msg += `  #${a.ad_id}: ${a.description}\n`);
}

return [{ json: { message: msg } }];
